import{_ as a,o as n,c as s,a2 as d}from"./chunks/framework.CQMe4Urg.js";const b=JSON.parse('{"title":"第 14 章 生产工程化","description":"","frontmatter":{},"headers":[],"relativePath":"14-production/index.md","filePath":"14-production/index.md","lastUpdated":1776333512000}'),e={name:"14-production/index.md"};function p(l,t,r,i,o,h){return n(),s("div",null,[...t[0]||(t[0]=[d(`<h1 id="第-14-章-生产工程化" tabindex="-1">第 14 章 生产工程化 <a class="header-anchor" href="#第-14-章-生产工程化" aria-label="Permalink to &quot;第 14 章 生产工程化&quot;">​</a></h1><p>你的 Agent 在 Jupyter Notebook 里跑得很顺畅——响应快、效果好、Demo 惊艳。然后老板说&quot;下周上线&quot;，你才发现从原型到生产之间隔着一道鸿沟。</p><p>生产环境里，单用户变成了数千并发用户，偶尔崩溃变成了 99.9% 的 SLA 承诺，&quot;无所谓&quot;的 API 费用变成了每月数万元的成本压力。本章就是帮你跨过这道鸿沟的桥梁。</p><p>我们会从最基础的项目结构和环境变量管理开始，教你把一个 Python 脚本变成一个可部署的服务；然后进入架构设计和容错体系，让你的服务在各种异常情况下都能优雅应对；最后深入成本控制、高可用架构和自动化发布流程，打造真正的生产级系统。</p><h2 id="本章结构" tabindex="-1">本章结构 <a class="header-anchor" href="#本章结构" aria-label="Permalink to &quot;本章结构&quot;">​</a></h2><table tabindex="0"><thead><tr><th>层级</th><th>内容</th><th>适合读者</th></tr></thead><tbody><tr><td><a href="./beginner.html">入门篇</a></td><td>项目结构、环境变量管理、基本错误处理、日志规范</td><td>第一次部署 Agent 服务的开发者</td></tr><tr><td><a href="./intermediate.html">进阶篇</a></td><td>架构设计、完善的容错体系（重试/降级/熔断）、容器化部署</td><td>需要保证服务稳定性的工程师</td></tr><tr><td><a href="./advanced.html">高级篇</a></td><td>成本控制、高可用架构、灰度发布、CI/CD、自动扩缩容</td><td>负责大规模 Agent 服务的架构师</td></tr></tbody></table><h2 id="从原型到生产的关键差异" tabindex="-1">从原型到生产的关键差异 <a class="header-anchor" href="#从原型到生产的关键差异" aria-label="Permalink to &quot;从原型到生产的关键差异&quot;">​</a></h2><table tabindex="0"><thead><tr><th>维度</th><th>原型阶段</th><th>生产阶段</th></tr></thead><tbody><tr><td>并发</td><td>单用户交互</td><td>数千并发用户</td></tr><tr><td>可靠性</td><td>偶尔崩溃可接受</td><td>99.9% SLA 承诺</td></tr><tr><td>成本</td><td>无预算限制</td><td>每请求成本敏感</td></tr><tr><td>安全</td><td>信任所有输入</td><td>防注入、防滥用</td></tr><tr><td>可观测</td><td>print 调试</td><td>结构化日志 + 分布式追踪</td></tr><tr><td>部署</td><td>本地运行</td><td>Docker + CI/CD 自动化</td></tr><tr><td>配置</td><td>硬编码</td><td>环境变量 + 配置中心</td></tr></tbody></table><h2 id="生产化路线图" tabindex="-1">生产化路线图 <a class="header-anchor" href="#生产化路线图" aria-label="Permalink to &quot;生产化路线图&quot;">​</a></h2><p>一个 Agent 从 Demo 到生产，通常需要经历这些阶段：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>阶段1 - 脚本可用（入门篇）</span></span>
<span class="line"><span>├── 标准项目结构</span></span>
<span class="line"><span>├── 配置管理（.env + Pydantic Settings）</span></span>
<span class="line"><span>├── 基础错误处理</span></span>
<span class="line"><span>├── 结构化日志</span></span>
<span class="line"><span>└── FastAPI HTTP 接口</span></span>
<span class="line"><span></span></span>
<span class="line"><span>阶段2 - 服务可靠（进阶篇）</span></span>
<span class="line"><span>├── 分层架构设计</span></span>
<span class="line"><span>├── 完善容错（重试 / 超时 / 熔断 / 降级）</span></span>
<span class="line"><span>├── 数据库集成（SQLAlchemy + Redis）</span></span>
<span class="line"><span>├── 异步任务队列</span></span>
<span class="line"><span>├── Docker 容器化</span></span>
<span class="line"><span>└── CI/CD 管道</span></span>
<span class="line"><span></span></span>
<span class="line"><span>阶段3 - 规模可扩（高级篇）</span></span>
<span class="line"><span>├── 高可用架构</span></span>
<span class="line"><span>├── 灰度发布策略</span></span>
<span class="line"><span>├── 成本优化体系</span></span>
<span class="line"><span>├── 自动扩缩容</span></span>
<span class="line"><span>├── 多租户隔离</span></span>
<span class="line"><span>└── Kubernetes 编排</span></span></code></pre></div><h2 id="你将学到的核心技能" tabindex="-1">你将学到的核心技能 <a class="header-anchor" href="#你将学到的核心技能" aria-label="Permalink to &quot;你将学到的核心技能&quot;">​</a></h2><ul><li><strong>入门篇</strong>：把脚本变成可部署的 HTTP 服务，有配置管理、错误处理和日志</li><li><strong>进阶篇</strong>：构建分层架构，实现容错体系和容器化部署，让服务稳定可靠</li><li><strong>高级篇</strong>：掌握高可用、灰度发布和成本优化，支撑大规模 Agent 平台</li></ul><h2 id="常见的生产事故-以及如何避免" tabindex="-1">常见的生产事故（以及如何避免） <a class="header-anchor" href="#常见的生产事故-以及如何避免" aria-label="Permalink to &quot;常见的生产事故（以及如何避免）&quot;">​</a></h2><table tabindex="0"><thead><tr><th>事故类型</th><th>原因</th><th>预防措施</th></tr></thead><tbody><tr><td>API Key 泄露</td><td>硬编码在代码中</td><td>环境变量 + Secret Manager</td></tr><tr><td>雪崩式故障</td><td>一个服务挂了拖垮整个系统</td><td>熔断器 + 降级策略</td></tr><tr><td>账单爆炸</td><td>死循环调用 LLM</td><td>Token 上限 + 费用告警</td></tr><tr><td>数据丢失</td><td>没有持久化</td><td>数据库 + 定期备份</td></tr><tr><td>服务不可用</td><td>单点故障</td><td>多实例 + 负载均衡</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">工程化不是一蹴而就的</p><p>不需要一上来就搭建完美的架构。从入门篇开始，先让服务能跑起来，再逐步加固。过度工程化和工程化不足一样有害——前者浪费时间，后者出了事没法修。</p></div>`,16)])])}const u=a(e,[["render",p]]);export{b as __pageData,u as default};
